import { html, customElement, property, css, when } from '@umbraco-cms/backoffice/external/lit';
import type { UmbPropertyEditorUiElement } from '@umbraco-cms/backoffice/property-editor';
import { UmbLitElement } from '@umbraco-cms/backoffice/lit-element';
import { UUIInputPasswordElement } from '@umbraco-cms/backoffice/external/uui';

const elementName = "forms-password-property-editor";

@customElement(elementName)
export class FormsPasswordPropertyUiElement extends UmbLitElement implements UmbPropertyEditorUiElement {

  #value: string = "";

  @property({ type: String })
  get value() { return this.#value; }
  set value(value: string) {
    let oldVal = this.#value;
    this.#value = value;
    this.requestUpdate('value', oldVal);
  }

  #onChange(e: CustomEvent) {
    const value = (e.target as UUIInputPasswordElement).value.toString();
    this.value = value;
    this.dispatchEvent(new CustomEvent('property-value-change'));
  }

  render() {
    return html`<uui-input-password value="${this.value}" @change=${this.#onChange}></uui-input-password>`;
  }
}

export default FormsPasswordPropertyUiElement;

declare global {
    interface HTMLElementTagNameMap {
        [elementName]: FormsPasswordPropertyUiElement;
    }
}
